dtsPropsFor.Table:
/** Row data to render. The table is generic over the row type; rows are virtualized. */
rows: readonly unknown[];
/** Column definitions: an id, a header node, optional sizing, and a per-row cell renderer. */
columns: ReadonlyArray<{
  id: string;
  header: React.ReactNode;
  /** Fixed column width in px. */
  width?: number;
  /** Minimum width in px when the column flexes (default 200). */
  minWidth?: number;
  /** Renders the cell content for a row. */
  cell: (row: unknown) => React.ReactNode;
  /** Provide to make the column sortable; returns the sort key for a row. */
  sortBy?: (row: unknown) => string | number;
}>;
/** Stable unique key for a row (used for React keys and virtualization). */
rowKey: (row: unknown) => string;
/** Row height in px (default 36). */
rowHeight?: number;
/** Rendered when there are no rows. */
emptyState?: React.ReactNode;
/** Controlled global filter text. Pair with globalFilterFn. */
globalFilter?: string;
/** Predicate deciding whether a row matches the current filter text. */
globalFilterFn?: (row: unknown, value: string) => boolean;
/** Controlled sorting state: an array of { id, desc } entries. Pair with onSortingChange. */
sorting?: ReadonlyArray<{ id: string; desc: boolean }>;
/** Called with the next sorting state when the user toggles a sortable header. */
onSortingChange?: (next: ReadonlyArray<{ id: string; desc: boolean }>) => void;
